'use client'

import React, { useRef, useEffect, useCallback, useState } from 'react'
import { Canvas, useThree, useFrame } from '@react-three/fiber'
import { Environment, Center } from '@react-three/drei'
import { degToRad } from 'three/src/math/MathUtils'
import gsap from 'gsap'
import { EffectComposer } from '@react-three/postprocessing'
import RoomModel from './room-model'
import CustomGrainNoise from './custom-grain-noise'
import EdgeBlurEffect from './edge-blur-effect'
import VideoUI from './video-ui'

const ENV_INTENSITY_CONFIG = {
  zoomed: 0,
  out: 0.1,
  lightZoomed: 0,
  lightOut: 3,
}

function MovingPointLight({ lightRef }) {
  const { gl } = useThree()
  const targetRef = useRef({ x: 0, y: 0 })

  const handlePointerMove = useCallback((event) => {
    const rect = gl.domElement.getBoundingClientRect()
    targetRef.current.x = ((event.clientX - rect.left) / rect.width) * 2 - 1
    targetRef.current.y = -((event.clientY - rect.top) / rect.height) * 2 + 1
  }, [gl])

  useEffect(() => {
    const dom = gl.domElement
    dom.addEventListener('mousemove', handlePointerMove)
    return () => dom.removeEventListener('mousemove', handlePointerMove)
  }, [gl, handlePointerMove])

  useFrame(() => {
    const light = lightRef.current
    if (!light) return
    const basePos = { x: 0, y: -1.3, z: -2 }
    const spread = { x: 1.8, y: 0.0, z: 0.08 }
    const tx = basePos.x + targetRef.current.x * spread.x
    const tz = basePos.z + targetRef.current.y * spread.z
    light.position.x += (tx - light.position.x) * 0.1
    light.position.z += (tz - light.position.z) * 0.1
  })

  return (
    <pointLight
      ref={lightRef}
      castShadow
      position={[0, -1.3, -2]}
      distance={100}
      decay={0.7}
      color="#fff"
    />
  )
}

function SceneContent({ isZoomed, setIsZoomed, videoRef }) {
  const groupRef = useRef()
  const lightRef = useRef()
  const { camera, scene } = useThree()

  const intensityState = useRef({
    env: ENV_INTENSITY_CONFIG.out,
    light: ENV_INTENSITY_CONFIG.lightOut,
  })

  const handleModelClick = useCallback((e) => {
    e?.stopPropagation()
    setIsZoomed(prev => !prev)
  }, [setIsZoomed])

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') setIsZoomed(false)
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [setIsZoomed])

  useEffect(() => {
    const duration = 1.5
    const ease = 'power3.inOut'

    gsap.killTweensOf(camera.position)
    if (groupRef.current) gsap.killTweensOf(groupRef.current.rotation)

    if (isZoomed) {
      gsap.to(camera.position, { x: 0, y: 0.05, z: 2.5, duration, ease })
      gsap.to(groupRef.current.rotation, { x: 0, y: 0, z: 0, duration, ease })
    } else {
      gsap.to(camera.position, { x: 0, y: 0, z: 4.8, duration, ease })
      gsap.to(groupRef.current.rotation, { x: 0, y: 0, z: degToRad(-5), duration, ease })
    }

    gsap.to(intensityState.current, {
      env: isZoomed ? ENV_INTENSITY_CONFIG.zoomed : ENV_INTENSITY_CONFIG.out,
      light: isZoomed ? ENV_INTENSITY_CONFIG.lightZoomed : ENV_INTENSITY_CONFIG.lightOut,
      duration,
      ease,
    })
  }, [isZoomed, camera])

  useFrame(() => {
    scene.environmentIntensity = intensityState.current.env
    if (lightRef.current) {
      lightRef.current.intensity = intensityState.current.light
    }
  })

  return (
    <>
      <MovingPointLight lightRef={lightRef} />
      <Environment
        background={false}
        files="https://dl.polyhaven.org/file/ph-assets/HDRIs/exr/1k/wooden_studio_08_1k.exr"
        environmentRotation={[0, degToRad(40), 0]}
      />
      <group ref={groupRef} rotation={[0, 0, degToRad(-5)]}>
        <RoomModel
          onClick={handleModelClick}
          isZoomed={isZoomed}
          videoRef={videoRef}
        />
      </group>
    </>
  )
}

export function Hero601() {
  const [isZoomed, setIsZoomed] = useState(false)
  const videoRef = useRef(null)

  return (
    <section className="w-full h-screen bg-black">
      <Canvas dpr={[1, 2]} camera={{ position: [0, 0, 4.8], fov: 55 }}>
        <Center>
          <SceneContent
            isZoomed={isZoomed}
            setIsZoomed={setIsZoomed}
            videoRef={videoRef}
          />
        </Center>
        <EffectComposer>
          <EdgeBlurEffect blurType="classic" blurStrength={1.5} blurStart={0.4} />
          <CustomGrainNoise amount={0.01} scale={1.5} opacity={0.9} />
        </EffectComposer>
      </Canvas>
      <VideoUI
        videoRef={videoRef}
        isZoomed={isZoomed}
        setIsZoomed={setIsZoomed}
      />
    </section>
  )
}

import { useMemo, useEffect } from "react";
import { Effect } from "postprocessing";
import { Uniform, Vector2 } from "three";

const fragmentShader = /* glsl */ `
uniform float uTime;
uniform float uAmount;
uniform float uScale;
uniform float uOpacity;
uniform vec2 uResolution;

float hash21(vec2 p) {
  p = fract(p * vec2(123.34, 456.21));
  p += dot(p, p + 45.32);
  return fract(p.x * p.y);
}

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
  vec2 aspectUV = uv;
  float aspect = uResolution.x / uResolution.y;
  if (aspect > 1.0) {
    aspectUV.x = (uv.x - 0.5) * aspect + 0.5;
  } else {
    aspectUV.y = (uv.y - 0.5) / aspect + 0.5;
  }

  float dotPixelSize = 0.0015;
  vec2 grainUV = floor(aspectUV * uScale / dotPixelSize) * dotPixelSize / uScale;
  float n = hash21(grainUV + fract(uTime * 60.0));

  float g = (n - 0.5) * uAmount;
  vec3 col = inputColor.rgb + vec3(g);

  outputColor = vec4(mix(inputColor.rgb, col, uOpacity), inputColor.a);
}
`;

class FilmGrainEffectImpl extends Effect {
  constructor({ amount = 0.12, scale = 900.0, opacity = 0.25, resolution = [1280, 720] } = {}) {
    const uniforms = new Map([
      ["uTime", new Uniform(0)],
      ["uAmount", new Uniform(amount)],
      ["uScale", new Uniform(scale)],
      ["uOpacity", new Uniform(opacity)],
      ["uResolution", new Uniform(new Vector2(resolution[0], resolution[1]))],
    ]);
    super("FilmGrainEffect", fragmentShader, { uniforms });
    this._time = 0;
  }

  setResolution(width, height) {
    const uRes = this.uniforms.get("uResolution");
    if (uRes) uRes.value.set(width, height);
  }

  update(renderer, _inputBuffer, deltaTime) {
    this._time += deltaTime;
    if (this._time > 1000) this._time -= 1000;
    const uTime = this.uniforms.get("uTime");
    if (uTime) uTime.value = this._time;
    if (renderer && renderer.getSize) {
      const size = renderer.getSize(new Vector2());
      this.setResolution(size.x, size.y);
    }
  }
}

export default function CustomGrainNoise({ amount = 0.12, scale = 900, opacity = 0.7 } = {}) {
  const effect = useMemo(() => {
    let width = 1280, height = 720;
    if (typeof window !== "undefined") {
      width = window.innerWidth;
      height = window.innerHeight;
    }
    return new FilmGrainEffectImpl({ amount, scale, opacity, resolution: [width, height] });
  }, [amount, scale, opacity]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const update = () => effect.setResolution(window.innerWidth, window.innerHeight);
    window.addEventListener("resize", update);
    update();
    return () => window.removeEventListener("resize", update);
  }, [effect]);

  return <primitive object={effect} dispose={null} />;
}

import { useMemo, useEffect } from "react";
import { Effect } from "postprocessing";
import { Uniform, Vector2 } from "three";

const classicBlurFragmentShader = /* glsl */ `
uniform float uBlurStrength;
uniform float uBlurStart;
uniform vec2 uResolution;

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
  vec2 center = uv - 0.5;
  float dist = length(center);

  float blurAmount = smoothstep(uBlurStart, 0.75, dist) * uBlurStrength;

  if (blurAmount < 0.001) {
    outputColor = inputColor;
    return;
  }

  vec2 texelSize = vec2(1.0 / uResolution.x, 1.0 / uResolution.y);

  const int TAPS = 12;
  vec2 offsets[12];
  offsets[0]  = vec2(-0.326, -0.406);
  offsets[1]  = vec2(-0.840, -0.074);
  offsets[2]  = vec2(-0.696,  0.457);
  offsets[3]  = vec2(-0.203,  0.621);
  offsets[4]  = vec2( 0.962, -0.195);
  offsets[5]  = vec2( 0.473, -0.480);
  offsets[6]  = vec2( 0.519,  0.767);
  offsets[7]  = vec2( 0.185, -0.893);
  offsets[8]  = vec2( 0.507,  0.064);
  offsets[9]  = vec2( 0.896,  0.412);
  offsets[10] = vec2(-0.322, -0.933);
  offsets[11] = vec2(-0.792, -0.598);

  float radius = blurAmount * 12.0;
  vec4 blurred = inputColor;
  float totalWeight = 1.0;

  for (int i = 0; i < TAPS; i++) {
    vec2 offset = offsets[i] * radius * texelSize;
    vec4 s = texture2D(inputBuffer, uv + offset);
    blurred += s;
    totalWeight += 1.0;
  }

  blurred /= totalWeight;
  outputColor = blurred;
}
`;

const frostedBlurFragmentShader = /* glsl */ `
uniform float uBlurStrength;
uniform float uBlurStart;
uniform vec2 uResolution;

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
  vec2 center = uv - 0.5;
  float dist = length(center);

  float blurAmount = smoothstep(uBlurStart, 0.75, dist) * uBlurStrength;

  if (blurAmount < 0.001) {
    outputColor = inputColor;
    return;
  }

  vec2 texelSize = vec2(1.0 / uResolution.x, 1.0 / uResolution.y);

  const int TAPS = 12;
  vec2 offsets[12];
  offsets[0]  = vec2(-0.326, -0.406);
  offsets[1]  = vec2(-0.840, -0.074);
  offsets[2]  = vec2(-0.696,  0.457);
  offsets[3]  = vec2(-0.203,  0.621);
  offsets[4]  = vec2( 0.962, -0.195);
  offsets[5]  = vec2( 0.473, -0.480);
  offsets[6]  = vec2( 0.519,  0.767);
  offsets[7]  = vec2( 0.185, -0.893);
  offsets[8]  = vec2( 0.507,  0.064);
  offsets[9]  = vec2( 0.896,  0.412);
  offsets[10] = vec2(-0.322, -0.933);
  offsets[11] = vec2(-0.792, -0.598);

  float radius = blurAmount * 12.0;
  vec4 blurred = inputColor;
  float totalWeight = 1.0;

  for (int i = 0; i < TAPS; i++) {
    vec2 offset = offsets[i] * radius * texelSize;
    vec4 s = texture2D(inputBuffer, uv + offset);
    blurred += s;
    totalWeight += 1.0;
  }

  blurred /= totalWeight;

  vec3 white = vec3(1.0, 1.0, 1.0);
  float veilAlpha = 0.4 * blurAmount;
  vec3 outRgb = mix(blurred.rgb, white, veilAlpha);

  outputColor = vec4(outRgb, blurred.a);
}
`;

class EdgeBlurEffectImpl extends Effect {
  constructor({ blurStrength = 1.0, blurStart = 0.25, resolution = [1280, 720], frag = frostedBlurFragmentShader } = {}) {
    const uniforms = new Map([
      ["uBlurStrength", new Uniform(blurStrength)],
      ["uBlurStart", new Uniform(blurStart)],
      ["uResolution", new Uniform(new Vector2(resolution[0], resolution[1]))],
    ]);
    super("EdgeBlurEffect", frag, { uniforms });
  }

  setResolution(width, height) {
    const uRes = this.uniforms.get("uResolution");
    if (uRes) uRes.value.set(width, height);
  }

  update(renderer) {
    if (renderer && renderer.getSize) {
      const size = renderer.getSize(new Vector2());
      this.setResolution(size.x, size.y);
    }
  }
}

export default function EdgeBlurEffect({ blurType = "classic", blurStrength = 1.0, blurStart = 0.25 }) {
  const frag = blurType === "classic" ? classicBlurFragmentShader : frostedBlurFragmentShader;

  const effect = useMemo(() => {
    let width = 1280, height = 720;
    if (typeof window !== "undefined") {
      width = window.innerWidth;
      height = window.innerHeight;
    }
    return new EdgeBlurEffectImpl({ blurStrength, blurStart, resolution: [width, height], frag });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [blurStrength, blurStart, frag]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const update = () => effect.setResolution(window.innerWidth, window.innerHeight);
    window.addEventListener("resize", update);
    update();
    return () => window.removeEventListener("resize", update);
  }, [effect]);

  return <primitive object={effect} dispose={null} />;
}

'use client'

import React, { useRef, useEffect, useCallback } from "react";
import {
  useGLTF,
  useTexture,
  MeshReflectorMaterial,
  useVideoTexture,
  shaderMaterial,
} from "@react-three/drei";
import { useThree, useFrame, extend } from "@react-three/fiber";
import * as THREE from "three";
import gsap from "gsap";

const TVTransitionMaterial = shaderMaterial(
  {
    uTexA: null,
    uTexB: null,
    uProgress: 0,
    uOffset: new THREE.Vector2(),
    uTime: 0,
    uResolution: new THREE.Vector2(1, 1),
  },
  `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  `
    uniform sampler2D uTexA;
    uniform sampler2D uTexB;
    uniform float uProgress;
    uniform float uTime;
    uniform vec2 uOffset;
    varying vec2 vUv;

    vec2 pixelate(vec2 uv, float pixelSize) {
      return floor(uv / pixelSize) * pixelSize + pixelSize * 0.5;
    }

    void main() {
      vec2 uv = vUv;
      float p = clamp(uProgress, 0.0, 1.0);

      uv += uOffset * 0.05;

      float maxPixelSize = 0.2;
      float pixelSizeA = mix(0.0, maxPixelSize, smoothstep(0.0, 1.0, p));
      float pixelSizeB = mix(maxPixelSize, 0.0, smoothstep(0.0, 1.0, p));

      vec2 uvA = (uv - 0.5) * (1.0 + p * 0.05) + 0.5;
      vec2 uvB = (uv - 0.5) * (1.05 - p * 0.05) + 0.5;

      uvA = pixelate(uvA, max(pixelSizeA, 0.0001));
      uvB = pixelate(uvB, max(pixelSizeB, 0.0001));

      vec4 texA = texture2D(uTexA, uvA);
      vec4 texB = texture2D(uTexB, uvB);

      float fade = smoothstep(0.0, 1.0, p);
      vec4 col = mix(texA, texB, fade);

      gl_FragColor = col;

      #include <tonemapping_fragment>
      #include <colorspace_fragment>
    }
  `
);

extend({ TVTransitionMaterial });

export default function RoomModel({ onClick, isZoomed, videoRef, ...props }) {
  const groupRef = useRef();
  const tvMatRef = useRef();
  const { gl } = useThree();

  const { nodes } = useGLTF("/601/finall.glb");

  const TVtexture = useTexture("/601/tvtex2.png");
  TVtexture.colorSpace = THREE.SRGBColorSpace;
  TVtexture.flipY = false;

  const videoTexture = useVideoTexture(
    "https://media.fiddle.digital/uploads/feature_kaleida_f406072b29.mp4",
    { start: false }
  );
  videoTexture.colorSpace = THREE.SRGBColorSpace;
  videoTexture.flipY = false;

  useEffect(() => {
    if (!videoTexture?.image) return;
    videoRef.current = videoTexture.image;
    videoTexture.image.preload = "auto";
    videoTexture.image.load();
  }, [videoTexture]);

  useEffect(() => {
    if (!videoTexture?.image) return;
    if (isZoomed) {
      setTimeout(() => { videoTexture.image.play(); }, 300);
    } else {
      videoTexture.image.pause();
    }
  }, [isZoomed]);

  const progressRef = useRef({ value: 0 });
  const animate = useRef();

  useEffect(() => {
    animate.current = gsap.quickTo(progressRef.current, "value", {
      duration: 1.5,
      ease: "power4.inOut",
    });
  }, []);

  useEffect(() => {
    animate.current?.(isZoomed ? 1 : 0);
  }, [isZoomed]);

  const targetRot = useRef({ x: 0, y: 0 });
  const targetOffset = useRef({ x: 0, y: 0 });
  const offsetRef = useRef({ x: 0, y: 0 });

  const handlePointerMove = useCallback(
    (e) => {
      if (isZoomed) return;
      const rect = gl.domElement.getBoundingClientRect();
      const x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
      const y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
      targetRot.current.x = -y * 0.05;
      targetRot.current.y = x * 0.15;
      targetOffset.current.x = x * 0.04;
      targetOffset.current.y = y * 0.02;
    },
    [gl, isZoomed]
  );

  useEffect(() => {
    gl.domElement.addEventListener("mousemove", handlePointerMove);
    return () => gl.domElement.removeEventListener("mousemove", handlePointerMove);
  }, [handlePointerMove, gl]);

  useEffect(() => {
    if (isZoomed) {
      gsap.to(targetRot.current, { x: 0, y: 0, duration: 0.5, overwrite: true, ease: "power3.out" });
      gsap.to(targetOffset.current, { x: 0, y: 0, duration: 0.5, overwrite: true, ease: "power3.out" });
    }
  }, [isZoomed]);

  useFrame((_, delta) => {
    if (groupRef.current) {
      groupRef.current.rotation.x += (targetRot.current.x - groupRef.current.rotation.x) * 0.05;
      groupRef.current.rotation.y += (targetRot.current.y - groupRef.current.rotation.y) * 0.05;
    }
    offsetRef.current.x += (targetOffset.current.x - offsetRef.current.x) * 0.08;
    offsetRef.current.y += (targetOffset.current.y - offsetRef.current.y) * 0.08;
    if (tvMatRef.current) {
      tvMatRef.current.uOffset.set(offsetRef.current.x, offsetRef.current.y);
      tvMatRef.current.uTime += delta;
      tvMatRef.current.uProgress = progressRef.current.value;
    }
  });

  const normalMap = useTexture("/601/normal.webp");
  normalMap.colorSpace = THREE.NoColorSpace;

  const baseMat = {
    color: "#000",
    normalMap,
    normalScale: new THREE.Vector2(0.3, 0.3),
    roughness: 10.0,
    side: THREE.DoubleSide,
  };

  const roughnessMap = useTexture(
    "https://png.pngtree.com/png-clipart/20241204/original/pngtree-textured-background-of-bathroom-floor-tiles-png-image_17548659.png"
  );
  roughnessMap.wrapS = roughnessMap.wrapT = THREE.RepeatWrapping;
  roughnessMap.repeat.set(4, 4);

  return (
    <group ref={groupRef} {...props} dispose={null}>
      <mesh geometry={nodes.room.geometry}>
        <meshStandardMaterial {...baseMat} />
      </mesh>
      <mesh geometry={nodes.Door.geometry}>
        <meshStandardMaterial {...baseMat} />
      </mesh>
      <mesh position={[0, 0, 1]} geometry={nodes.ladder.geometry}>
        <meshStandardMaterial {...baseMat} />
      </mesh>
      <mesh geometry={nodes.Body4002.geometry}>
        <meshStandardMaterial {...baseMat} />
      </mesh>
      <mesh geometry={nodes.Body4002_1.geometry}>
        <meshStandardMaterial {...baseMat} />
      </mesh>
      <mesh geometry={nodes.Body4002_2.geometry}>
        <meshStandardMaterial {...baseMat} />
      </mesh>

      <group
        onClick={onClick}
        onPointerEnter={() => (document.body.style.cursor = "pointer")}
        onPointerLeave={() => (document.body.style.cursor = "auto")}
      >
        <mesh geometry={nodes.screen.geometry}>
          <meshStandardMaterial {...baseMat} />
        </mesh>
        <mesh geometry={nodes.tv.geometry}>
          <tVTransitionMaterial
            ref={tvMatRef}
            uTexA={TVtexture}
            uTexB={videoTexture}
          />
        </mesh>
      </group>

      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]}>
        <planeGeometry args={[4.2, 10]} />
        <MeshReflectorMaterial
          resolution={1024}
          blur={[200, 50]}
          mixBlur={2}
          mixStrength={100}
          roughness={0.1}
          distortionMap={roughnessMap}
          distortion={0.0}
          reflectorOffset={0}
          color="#111"
          metalness={0.9}
        />
      </mesh>
    </group>
  );
}

import React, { useRef, useEffect } from 'react';

export default function VideoUI({ isZoomed, setIsZoomed, videoRef }) {
  const progressRef = useRef(null);

  useEffect(() => {
    let rafId;

    const tick = () => {
      const video = videoRef?.current;
      const bar = progressRef.current;

      if (bar && video && video.duration > 0 && !isNaN(video.duration)) {
        const pct = (video.currentTime / video.duration) * 100;
        bar.style.width = `${pct}%`;
      }

      rafId = requestAnimationFrame(tick);
    };

    rafId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafId);
  }, [videoRef]);

  return (
    <>
      <p className={`absolute top-[2vw] left-1/2 -translate-x-1/2 uppercase text-white/50 transition-opacity duration-1000 text-xs ${isZoomed ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
        [ESC] to back
      </p>
      <div className={`absolute bottom-0 left-0 w-full p-8 flex justify-between items-center text-white/50 text-xs font-mono transition-opacity duration-1000 ${isZoomed ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
        <div className="flex items-center gap-2">
          <span className="uppercase">HYPERIUX IMMERSION LABS</span>
        </div>
        <button
          onClick={() => setIsZoomed(false)}
          className="hover:text-white transition-colors cursor-pointer"
        >
          GO BACK
        </button>
        <div className="absolute bottom-0 left-0 h-[5px] bg-orange-500/20 w-full">
          <div
            ref={progressRef}
            className="h-full bg-orange-500"
            style={{ width: '0%', transition: 'none' }}
          />
        </div>
      </div>
    </>
  );
}
